+func (h *templateTestHelper) createHierarchy(rootID string, descendantIDs ...string) {
+	h.createIssueWithID(rootID, rootID, "", types.TypeEpic, 1)
+	for _, id := range descendantIDs {
+		h.createIssueWithID(id, id, "", types.TypeTask, 2)
+	}
+}
